     3|const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000
     4|const RATE_LIMIT_MAX = 10
     5|const ipBuckets = new Map<string, { count: number; resetAt: number }>()
     6|
     7|function getRateLimitInfo(ip: string): { allowed: boolean; remaining: number; resetAt: number } {
     8|  const now = Date.now()
     9|  const bucket = ipBuckets.get(ip)
    10|  if (!bucket || now > bucket.resetAt) {
    11|    ipBuckets.set(ip, { count: 1, resetAt: now + RATE_LIMIT_WINDOW_MS })
    12|    return { allowed: true, remaining: RATE_LIMIT_MAX - 1, resetAt: now + RATE_LIMIT_WINDOW_MS }
    13|  }
    14|  const allowed = bucket.count < RATE_LIMIT_MAX
    15|  if (allowed) bucket.count++
    16|  return { allowed, remaining: Math.max(0, RATE_LIMIT_MAX - bucket.count), resetAt: bucket.resetAt }
    17|}
