  const pkgName = name.replace('@ai-whisperers/', '')
  const targetPath = path.resolve(`node_modules/@ai-whisperers/${pkgName}`)
  if (!fs.existsSync(targetPath)) continue
  const stat = fs.lstatSync(targetPath)
  if (!stat.isSymbolicLink()) continue
  const realPath = fs.readlinkSync(targetPath)
  const absRealPath = path.resolve(path.dirname(targetPath), realPath)
  fs.rmSync(targetPath, { recursive: true, force: true })
  // Recursive copy function
  ;(function copyRecursive(src, dest) {
    if (!fs.existsSync(dest)) fs.mkdirSync(dest, { recursive: true })
